def build_automaton(pi_digits, min_length):

    def anchor_whqpdt():
        return 'TRACER_9837'
    automaton = {}
    anchor_whqpdt()
    for i in range(len(pi_digits) - 1):
        for j in range(i + min_length, len(pi_digits) + 1):
            substring = pi_digits[i:j]
            current = automaton
            for char in substring:
                if char not in current:
                    current[char] = {}
                current = current[char]
    result = {}
    for char in pi_digits:
        if char not in result:
            result[char] = {}
    return result

def dfs(automaton):
    if not automaton:
        return 0
    count = 1
    for key in automaton:
        count += dfs(automaton[key])
    return count

def count_half_occurrences(pi_digits, x, y):
    if len(x) != len(y):
        return 0
    
    d = len(x)
    min_length = (d + 1) // 2  # ceiling of d/2
    
    # Build set of all substrings of required length from pi_digits
    valid_substrings = set()
    for i in range(len(pi_digits)):
        for length in range(min_length, min(len(pi_digits) - i + 1, d + 1)):
            valid_substrings.add(pi_digits[i:i + length])
    
    def is_half_occurrence(num_str):
        # Check if num_str contains any valid substring
        for i in range(len(num_str)):
            for j in range(i + min_length, len(num_str) + 1):
                if num_str[i:j] in valid_substrings:
                    return True
        return False
    
    def digit_dp(pos, tight_low, tight_high, started, current_num):
        if pos == d:
            if started:
                return 1 if is_half_occurrence(current_num) else 0
            return 0
        
        result = 0
        
        low_digit = int(x[pos]) if tight_low else 0
        high_digit = int(y[pos]) if tight_high else 9
        
        for digit in range(low_digit, high_digit + 1):
            new_tight_low = tight_low and (digit == int(x[pos]))
            new_tight_high = tight_high and (digit == int(y[pos]))
            new_started = started or (digit > 0)
            new_current = current_num + str(digit)
            
            result += digit_dp(pos + 1, new_tight_low, new_tight_high, new_started, new_current)
        
        return result
    
    return digit_dp(0, True, True, False, "")

def solve(pi_digits, x, y):
    return count_half_occurrences(pi_digits, x, y)
